            .WithMany(channelInfo => channelInfo.Distributions)
            .HasForeignKey(channelDistribution => channelDistribution.ChannelId)
            .OnDelete(DeleteBehavior.Cascade)
            .HasConstraintName("FK_ChannelDistributions_ChannelInfos");
        
        //  Настройка идентификатора свойства "Информация о фильтре".
        typeBuilder.Property(channelDistribution => channelDistribution.FilterId);
        typeBuilder.HasIndex(channelDistribution => channelDistribution.FilterId);
        
        //  Настройка свойства "Информация о фильтре".
        typeBuilder.HasOne(channelDistribution => channelDistribution.Filter)
            .WithMany(filterInfo => filterInfo.Distributions)
            .HasForeignKey(channelDistribution => channelDistribution.FilterId)
            .OnDelete(DeleteBehavior.Cascade)
            .HasConstraintName("FK_ChannelDistributions_FilterInfos");
        
        //  Настройка идентификатора свойства "Информация о метрике файла".
        typeBuilder.Property(channelDistribution => channelDistribution.FileMetricId);
        typeBuilder.HasIndex(channelDistribution => channelDistribution.FileMetricId);
        
        //  Настройка свойства "Информация о метрике файла".
        typeBuilder.HasOne(channelDistribution => channelDistribution.FileMetric)
            .WithMany(internalFileMetric => internalFileMetric.Distributions)
            .HasForeignKey(channelDistribution => channelDistribution.FileMetricId)
            .OnDelete(DeleteBehavior.Cascade)
            .HasConstraintName("FK_ChannelDistributions_InternalFileMetrics");
        
        //  Настройка ключа "Уникальная комбинация канала, фильтра и метрики файла".
        typeBuilder.HasAlternateKey(channelDistribution => new
        {
            channelDistribution.ChannelId,
            channelDistribution.FilterId,
            channelDistribution.FileMetricId,
        });
        
    }
    
